// ── ImagesService.gs ──────────────────────────────────────
// Returns brand logos as base64 data URIs so they can be
// embedded inline in the HTML template via scriptlets.
// This avoids any CORS / hotlinking issues with external URLs.

const LOGO_WHITE_B64 = 'data:image/png;base64,';
const LOGO_BLUE_B64  = 'data:image/png;base64,';

function getLogoWhite() { return LOGO_WHITE_B64; }
function getLogoBlue()  { return LOGO_BLUE_B64;  }
